import React from 'react';
import { useTranslation } from 'react-i18next';

const VerificationBadge = ({ verified = true, className = '' }) => {
  const { t } = useTranslation();
  
  if (verified) {
    return (
      <div className={`flex items-center bg-green-100 text-green-800 text-xs font-medium px-2.5 py-0.5 rounded-full ${className}`}>
        <svg className="w-3 h-3 mr-1 text-green-700" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd"></path>
        </svg>
        {t('certificatesPage.verified')}
      </div>
    );
  }
  
  return (
    <div className={`flex items-center bg-red-100 text-red-800 text-xs font-medium px-2.5 py-0.5 rounded-full ${className}`}>
      <svg className="w-3 h-3 mr-1 text-red-700" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd"></path>
      </svg>
      {t('certificatesPage.unverified')}
    </div>
  );
};

export default VerificationBadge;
